extra.modelCss:
/* Box model na prática */

* {
  box-sizing: border-box;
}

.card {
  padding: 16px;          /* espaço interno */
  border: 1px solid #ddd; /* borda */
  border-radius: 14px;
  margin: 16px 0;         /* espaço externo */
}

.badge {
  display: inline-block;
  padding: 6px 10px;
  border: 1px solid #bbb;
  border-radius: 999px;
}
